import{_ as r}from"./nyalra_kb-7135827b.js";import{_ as p}from"./nyalra_no_mono-8344e451.js";import{_ as c,W as s,X as _,Y as i,Z as e,$ as t,a0 as o,a2 as m,a1 as d,C as a}from"./framework-a4c02b8f.js";const f={},u=e("figure",null,[e("img",{src:r,alt:"",tabindex:"0",loading:"lazy"}),e("figcaption")],-1),h={href:"https://tree-novel.com/works/episode/d796e00471cd903db661d68f16e46ed9.html",target:"_blank",rel:"noopener noreferrer"},k=e("p",null,"这是在互联网中栖息的不可思议生物·Nyalra于深夜写下的有关互联网、独居生活以及除此之外的事物的图文随笔。",-1),g=d('<hr><p>在推崇匿名文化的互联网上，基本上是不鼓励「谈论自己」的。但就是在这个时候，你会突然接触到陌生人的自言自语，每个人的生活都绝对是有趣的。实际上，每个人通过将自己与他人进行比较，来认识事物和常识的标准。信息越多越好。你的思考方式，你的成长经历一定会对某人有所帮助。</p><p>由于每个人的成长方式和环境都不同，所以所谓的「普通人生」是不存在的。无论是积极的方向，还是消极的方向，对于他人来说都可能是一种刺激。特别是在消极方向……复杂的情感可以成为创作和技术的动力，通过展示自己的伤痛也可以缓解创伤。</p><p>然而，频繁地进行自我陈述确实会让人感到厌烦。最理想的情况是，能够通过文章或视频轻松地展现自己。毕竟，谈论自己的人生和本质，还是尽量不希望给受众额外的压力。当然，想让别人了解自己，最好的方式可能是从头开始讲述，但为了吸引他人倾听，不可避免地需要削减冗长的部分，并为故事设置起伏和余韵。这个方面会在后文中提到。</p><p>剩下的就看你如何成文了，但只要你出生在日本，并对互联网有一定的了解，就能做到这一点。多多阅读一些你喜欢的作家的随笔，抓住你喜欢的文风。好的文章之所以好，我认为关键在于，相比插图，它能够更迅速地呈现出可见的形式。如果仍然感到不安，不妨再额外阅读一两本关于写作技巧的书籍。比如，『「文章術のベストセラー100冊」のポイントを1冊にまとめてみた。』，简洁而且值得推荐。</p><p>通常来说，一篇文章字数大约在4000字左右，是读者能够投入精力仔细阅读的极限。个人认为这也稍微有点长，所以考虑在3000字以下。2000左右可能正好。我理解你想要尽可能多地包含你喜欢的事物，但就像打卡牌游戏一样，基本上保持卡组的数量在最低限度是更为有效的。</p><p>那么，关于正文的重要一点是，其实有一些做文章评价的技巧。我成功地使用了这一技巧，所以在读书感想文方面也曾获得过一些不错的奖项。这个技巧简而言之就是「真实的个人观点」。人们非常喜欢接触他人真实的情感。就连读书感想文也是如此，通过不是写关于书本的内容，而是用书本作为踏板，展开真实的个人故事，可以显著改变文章的效果。将你的感性投射进去吧。</p><p>没问题，每个人的真实感受绝对都很有趣。过于掩饰才会导致感想变得平淡无奇。如果想要更加精准地表达当时的感受，可以坦率地表达，并且可以使用同义词词典（在网上有很多资源）来使表达更为准确。</p><p>刚才提到要制造文章的起伏，自我叙述的高潮部分通常是自己感情最为激动的场景。在构建文章时，可以设想将这一部分作为副歌，使其成为文章的高潮。</p><p>文章的结尾非常重要。是否通过巧妙而潇洒的一句来结束，将直接影响读者的评价。结尾好的话，一切都会变得美好，反之亦然。在处理结尾时，我们可以考虑，可以思考，可以深入思考。可以引用喜欢的作品台词或歌词，或者挑选出能够展示个人最高水平的一句话。从某种程度上说，这可能是最困难的部分，但这也是最需要专注的时刻，所以充满干劲地去完成吧！</p><p>然后，看吧，完成了。可以涉及对学校的怨恨、青春期的甜蜜体验、对喜欢的作品的热情等，主题可以是任何事物。接下来，只需修剪掉这段文字中不需要的部分。限制提供的信息，使之更加简练有力。删除创造出的文字是一种痛苦，但相信这样做绝对会使阅读更加轻松。通过这样的处理，你最想表达的内容，最重要的部分将更加突显。</p><hr><p><img src="'+p+'" alt="" loading="lazy"><img src="https://img.tree-novel.com/talk/0cc4038bac6abea58f366345bfa32492.jpg" alt="" loading="lazy"><img src="https://img.tree-novel.com/talk/01efd906f0686dca8778522224000550.jpg" alt="" loading="lazy"></p><blockquote><p>本周的にゃるら的物品：</p><p>『蒙德里安的拼图』皮特·蒙德里安的代表作双面拼图。原本，我对画作拼图不感兴趣，因为通常会有分割线，但在蒙德里安的情况下，这些线条也成为了一种风格，通过亲自组装，希望能看到一些不同。难度极高。总之，我了解到，拼图的难度与颜色的少与多有关。</p></blockquote>',14);function b(x,y){const n=a("ExternalLinkIcon"),l=a("RouterLink");return s(),_("div",null,[i(" more "),u,e("p",null,[t("原文链接："),e("a",h,[t("第42回／自分語りは誰でも面白くなる"),o(n)])]),e("blockquote",null,[k,e("p",null,[o(l,{to:"/posts/Translate/nyalra_kb_41.html"},{default:m(()=>[t("【奈亚拉面壁自语】第41回｜不能越过的界线【230829】")]),_:1})])]),g])}const z=c(f,[["render",b],["__file","nyalra_kb_42.html.vue"]]);export{z as default};
